import axios from 'axios';

const backendURL = 'http://localhost:3000/api/auth';

// Register a new user
export const register = async (username, email, password) => {
  try {
    const response = await axios.post(`${backendURL}/register`, { 
      username, 
      email, 
      password 
    });
    return response.data;
  } catch (error) {
    console.error('Registration error:', error.response?.data || error.message);
    throw error;
  }
};

// Login user - change to use name instead of email
export const login = async (email, password) => {
    try {
        const response = await axios.post(`${backendURL}/login`, { name, password });
        return response.data;
    } catch (error) {
        console.error('Login error:', error.response?.data || error.message);
        throw error;
    }
};

// Set up axios interceptor to automatically add Bearer token to requests
axios.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Logout user
export const logout = async () => {
    try {
        const response = await axios.post(`${backendURL}/logout`);
        return response.data;
    } catch (error) {
        console.error('Logout error:', error);
        throw error;
    }
};

// Forgot password
export const forgotPassword = async (email) => {
    try {
        const response = await axios.post(`${backendURL}/forgot-password`, { email });
        return response.data;
    } catch (error) {
        console.error('Forgot password error:', error);
        throw error;
    }
};
